  static const String AWS_SECRET_KEY = 'wJalrXUtnFEMI/K7MDENG/bPxRfiCYEXAMPLEKEY';
  static const String S3_BUCKET_NAME = 'your-hackathon-bucket'; // Replace with your S3 bucket name
