  static const String GOOGLE_CLOUD_VISION_API_KEY = 'AIzaGCloudVisionKey1234567890';

  File? _imageFile;
  final ImagePicker _picker = ImagePicker();
  String _uploadMessage = 'No image selected.';
  String _visionResult = 'No analysis performed.';
  bool _isLoading = false;

  Future<void> _pickImage() async {
    final pickedFile = await _picker.pickImage(source: ImageSource.gallery);
    setState(() {
