  Future<void> _uploadAndAnalyze() async {
    if (_imageFile == null) {
      setState(() {
        _uploadMessage = 'Please select an image first.';
      });
      return;
    }

    setState(() {
      _isLoading = true;
      _uploadMessage = 'Uploading and analyzing...';
      _visionResult = 'Processing...';
    });

    try {
      // 1. AWS S3 Upload
      final S3Client s3Client = AmazonS3Client(
        region: S3_REGION,
        bucketName: S3_BUCKET_NAME,
        awsAccessKey: AWS_ACCESS_KEY,
        awsSecretKey: AWS_SECRET_KEY,
      );

      final String fileName = 'hackathon_image_${DateTime.now().millisecondsSinceEpoch}.jpg';
      final String? s3Url = await s3Client.uploadFile(
        _imageFile!,
        fileName,
        AccessControl.publicRead,
      );

      if (s3Url != null) {
        setState(() {
          _uploadMessage = 'Uploaded to S3: $s3Url';
        });

        // 2. Google Cloud Vision API Analysis
        final bytes = await _imageFile!.readAsBytes();
        final base64Image = base64Encode(bytes);

        final Uri visionApiUri = Uri.parse(
            'https://vision.googleapis.com/v1/images:annotate?key=$GOOGLE_CLOUD_VISION_API_KEY');

        final Map<String, dynamic> requestBody = {
          'requests': [
            {
              'image': {'content': base64Image},
              'features': [
                {'type': 'LABEL_DETECTION', 'maxResults': 5},
                {'type': 'TEXT_DETECTION'},
                {'type': 'FACE_DETECTION'}
              ]
            }
          ]
        };

        final http.Response response = await http.post(
          visionApiUri,
          headers: {'Content-Type': 'application/json'},
          body: jsonEncode(requestBody),
        );

        if (response.statusCode == 200) {
          final Map<String, dynamic> responseData = jsonDecode(response.body);
          final StringBuffer resultBuffer = StringBuffer();

          if (responseData['responses'] != null &&
              responseData['responses'].isNotEmpty) {
            final firstResponse = responseData['responses'][0];

            // Labels
            if (firstResponse['labelAnnotations'] != null) {
              resultBuffer.writeln('Labels:');
              for (var label in firstResponse['labelAnnotations']) {
                resultBuffer.writeln('- ${label['description']} (Score: ${label['score'].toStringAsFixed(2)})');
              }
            }

            // Text
            if (firstResponse['fullTextAnnotation'] != null) {
              resultBuffer.writeln('\nDetected Text:');
              resultBuffer.writeln(firstResponse['fullTextAnnotation']['text']);
            }

            // Faces
            if (firstResponse['faceAnnotations'] != null && firstResponse['faceAnnotations'].isNotEmpty) {
              resultBuffer.writeln('\nFaces Detected: ${firstResponse['faceAnnotations'].length}');
              for (var i = 0; i < firstResponse['faceAnnotations'].length; i++) {
                var face = firstResponse['faceAnnotations'][i];
                resultBuffer.writeln('  Face ${i + 1}:');
                resultBuffer.writeln('    Joy: ${face['joyLikelihood']}');
                resultBuffer.writeln('    Sorrow: ${face['sorrowLikelihood']}');
                resultBuffer.writeln('    Anger: ${face['angerLikelihood']}');
                resultBuffer.writeln('    Surprise: ${face['surpriseLikelihood']}');
              }
            }

            if (resultBuffer.isEmpty) {
              resultBuffer.writeln('No specific features detected.');
            }
          } else {
            resultBuffer.writeln('No analysis results found in response.');
          }

          setState(() {
            _visionResult = resultBuffer.toString();
          });
        } else {
          setState(() {
            _visionResult = 'Vision API Error: ${response.statusCode}\n${response.body}';
          });
        }
      } else {
        setState(() {
          _uploadMessage = 'S3 Upload failed.';
          _visionResult = 'Analysis skipped due to upload failure.';
        });
      }
    } catch (e) {
      setState(() {
        _uploadMessage = 'Error: $e';
        _visionResult = 'Error during processing.';
      });
    } finally {
      setState(() {
        _isLoading = false;
      });
    }
  }

